spec.query:
from(bucket: "proxmox")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) =>
    r._measurement == "cpustat" and
    r._field == "cpu"
  )
  |> group(columns: ["host"])
  |> aggregateWindow(
    every: v.windowPeriod,
    fn: mean,
    createEmpty: false
  )
